#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, K, W;
        scanf("%d %d %d", &N, &K, &W);
        int* A = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        long long** dp = (long long**)malloc((N + 1) * sizeof(long long*));
        for (int i = 0; i <= N; i++) {
            dp[i] = (long long*)malloc((K) * sizeof(long long));
        }
        for (int i = 0; i <= N; i++) {
            for (int j = 0; j < K; j++) {
                dp[i][j] = 0;
            }
        }
        dp[0][0] = 1;
        long long ans = 0;
        for (int i = 1; i <= N; i++) {
            for (int j = 0; j < K; j++) {
                dp[i][j] = dp[i - 1][j];
                int sum = (j + A[i - 1]) % K;
                dp[i][sum] = (dp[i][sum] + dp[i - 1][j]) % MOD;
                if (i >= W + 1 && sum == 0) {
                    ans = (ans + dp[i - 1][j]) % MOD;
                }
            }
        }
        printf("%lld\n", ans);
        free(A);
        for (int i = 0; i <= N; i++) {
            free(dp[i]);
        }
        free(dp);
    }
    return 0;
}

